func loadSession(id string) (*Session, error) {
	sessionFile := filepath.Join("sessions", id+".gob")

	data, err := ioutil.ReadFile(sessionFile)
	if err != nil {
		return nil, err
	}

	var session Session
	err = gob.Unmarshal(data, &session)
	if err != nil {
		return nil, err
	}

	return &session, nil
}

func saveSession(session *sessions.Session, directory string) error {
	id := session.ID()
	sessionFile := filepath.Join(directory, id+".gob")

	data, err := gob.Marshal(session.Values)
	if err != nil {
		return err
	}

	err = ioutil.WriteFile(sessionFile, data, 0644)
	if err != nil {
		return err
	}

	return nil
}